const respondToFriendRequest = `-- name: RespondToFriendRequest :one
UPDATE friendships
SET status = $3
WHERE requester_id = $1 AND addressee_id = $2
RETURNING requester_id, addressee_id, status, created_at
`

type RespondToFriendRequestParams struct {
	RequesterID pgtype.UUID `json:"requester_id"`
	AddresseeID pgtype.UUID `json:"addressee_id"`
	Status      string      `json:"status"`
}

// Note the direction: only the addressee (the person who received the
// request) should be able to accept/decline it — enforced in Go, not SQL.
func (q *Queries) RespondToFriendRequest(ctx context.Context, arg RespondToFriendRequestParams) (Friendship, error) {
	row := q.db.QueryRow(ctx, respondToFriendRequest, arg.RequesterID, arg.AddresseeID, arg.Status)
	var i Friendship
	err := row.Scan(
		&i.RequesterID,
		&i.AddresseeID,
		&i.Status,
		&i.CreatedAt,
	)
	return i, err
}

const sendFriendRequest = `-- name: SendFriendRequest :one
INSERT INTO friendships (requester_id, addressee_id, status)
VALUES ($1, $2, 'pending')
ON CONFLICT (requester_id, addressee_id)
DO UPDATE SET status = 'pending', created_at = now()
RETURNING requester_id, addressee_id, status, created_at
`

type SendFriendRequestParams struct {
	RequesterID pgtype.UUID `json:"requester_id"`
	AddresseeID pgtype.UUID `json:"addressee_id"`
}

// ON CONFLICT lets someone re-send after a decline, refreshing it back to
// pending instead of erroring on the (requester_id, addressee_id) PK.
func (q *Queries) SendFriendRequest(ctx context.Context, arg SendFriendRequestParams) (Friendship, error) {
	row := q.db.QueryRow(ctx, sendFriendRequest, arg.RequesterID, arg.AddresseeID)
	var i Friendship
	err := row.Scan(
		&i.RequesterID,
		&i.AddresseeID,
		&i.Status,
		&i.CreatedAt,
	)
	return i, err
}

