const upsertRSVP = `-- name: UpsertRSVP :one
INSERT INTO event_rsvps (event_id, user_id, status)
VALUES ($1, $2, $3)
ON CONFLICT (event_id, user_id)
DO UPDATE SET status = EXCLUDED.status, requested_at = now()
RETURNING event_id, user_id, status, requested_at
`

type UpsertRSVPParams struct {
	EventID pgtype.UUID `json:"event_id"`
	UserID  pgtype.UUID `json:"user_id"`
	Status  string      `json:"status"`
}

// ON CONFLICT handles a user re-joining/re-leaving an event they already
// have an RSVP row for, updating their existing row instead of erroring
// on the (event_id, user_id) primary key collision.
func (q *Queries) UpsertRSVP(ctx context.Context, arg UpsertRSVPParams) (EventRsvp, error) {
	row := q.db.QueryRow(ctx, upsertRSVP, arg.EventID, arg.UserID, arg.Status)
	var i EventRsvp
	err := row.Scan(
		&i.EventID,
		&i.UserID,
		&i.Status,
		&i.RequestedAt,
	)
	return i, err
}
